  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=775 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;






CREATE TABLE `sales` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `customer_name` varchar(255) NOT NULL,
  `address` varchar(255) NOT NULL,
  `invoice_no` varchar(255) NOT NULL,
  `payment_type` varchar(255) NOT NULL,
  `customer_type` varchar(255) NOT NULL,
  `total` varchar(255) NOT NULL,
  `cash` varchar(255) NOT NULL,
  `transfer` varchar(255) NOT NULL,
  `pos` varchar(250) NOT NULL,
  `old_deposit` varchar(250) NOT NULL,
  `deposit` varchar(255) NOT NULL,
  `transport` varchar(250) NOT NULL,
  `balance` varchar(255) NOT NULL,
  `staff_name` varchar(255) NOT NULL,
  `date` varchar(255) NOT NULL,
  `username` varchar(255) NOT NULL,
