  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=19984 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;






CREATE TABLE `supply_check` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
